import{_ as t,o as i,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"View Through Attribution Testing","description":"","frontmatter":{"title":"View Through Attribution Testing","slug":"view-through-attribution-testing"},"headers":[],"relativePath":"marketer-hub/view-through-attribution-testing.md","filePath":"marketer-hub/view-through-attribution-testing.md"}'),o={name:"marketer-hub/view-through-attribution-testing.md"};function n(s,e,p,l,d,h){return i(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>View-through attribution(VTA) allows you to track installs, session starts and conversion events back to an ad impression, even if the ad was never clicked on. It’s important to understand the difference between View-through attribution(VTA) and Click-through attribution(CTA):</p><ul><li>VTA: The event attributed after a user VIEWED an ad within specified period of time</li><li>CTA: The event attributed after a user CLICKED on ad within specified period of time</li></ul><p>Be aware that events are attributed using Branch&#39;s unified last-click attribution model. This means that Branch view-through attribution logic works as follows for any given event:</p><ul><li>If there&#39;s a click within a valid attribution window, give credit to the click.</li><li>If there&#39;s no click within a valid attribution window, give credit to the last impression that was within a valid attribution window.</li></ul><p>Currently, view through attribution is supported for Self Attributing Networks (SANs), such as Facebook and Google, and non-SAN networks with server to server impression link support. Note: Branch doesn&#39;t support server to server impressions without device IDs.</p><p>To create an impression tracking link for non-SAN networks, simply create an ad link, and grab the impression link from the final step of link creation. SAN networks support VTA without any additional links.</p><p>As a part of our Ad Partners VTA verification process it’s essential to confirm that our integration works as expected and we deliver the best user experience. Because of that we want to guarantee the highest quality of Ad Partnership integrations and verify VTA verification process.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>For proper view through attribution, make sure the impression pixel returned by Branch&#39;s dashboard has an <code>%24idfa</code> OR <code>%24aaid</code> macro values. If you just want to count impressions, without attribution, these macros are not needed. The impression event has to drive conversion within the default Partner setting 1 day(24hrs) lookback window period.</p></div><h2 id="impression-tracking-url-testing" tabindex="-1">Impression Tracking URL Testing <a class="header-anchor" href="#impression-tracking-url-testing" aria-label="Permalink to &quot;Impression Tracking URL Testing&quot;">​</a></h2><ol><li><p>Get the Impression link from the final step of link creation on Branch Dashboard.</p></li><li><p>Add our tracking link to your system to generate <strong>ClickID</strong> and other <strong>parameters</strong> specified in the Branch <strong>Impression Link URL</strong>.</p></li><li><p>Ensure that Impression URL has a Device ID (<code>%24idfa=</code> OR <code>%24aaid=</code>) macro populated e.g. <code>idfa=AEBE52E7-03EE-455A-B3C4-E57283966239</code>:</p><p><code>https://impression.link/impression?branch_key=key_live_ljOlMvJZ565wI6bVcOuPYagjwsoHp4MX&amp;%243p=a_partner_name&amp;%24idfa=AEBE52E7-03EE-455A-B3C4-E57283966239&amp;~ad_set_id=[ad_set_id]&amp;~branch_ad_format=App%20Only&amp;~channel=Ogury&amp;~click_id=1234567890&amp;~feature=paid%20advertising](https://impression.link/impression?branch_key=key_live_ljOlMvJZ565wI6bVcOuPYagjwsoHp4MX&amp;%243p=a_partner_name&amp;%24idfa=AEBE52E7-03EE-455A-B3C4-E57283966239&amp;~ad_set_id=[ad_set_id]&amp;~branch_ad_format=App%20Only&amp;~channel=Ogury&amp;~click_id=1234567890&amp;~feature=paid%20advertising)</code></p></li><li><p>Click on that tracking URL with filled macro parameters on your mobile phone.</p></li><li><p>You&#39;ll be redirected to the 1x1 pixel web page to ensure view-through is tracked.</p></li><li><p>Navigate to the Google/Apple Store to install the Branch test application <strong>Branch Monster Factory</strong>.</p><ul><li>iOS: <a href="https://apps.apple.com/us/app/branch-monster-factory/id917737838?mt=8" target="_blank" rel="noreferrer">https://apps.apple.com/us/app/branch-monster-factory/id917737838?mt=8</a></li><li>Android: <a href="https://play.google.com/store/apps/details?id=io.branch.branchster" target="_blank" rel="noreferrer">https://play.google.com/store/apps/details?id=io.branch.branchster</a></li></ul></li><li><p>Open an app so that Branch attribute view through to install event.</p></li></ol><p>Please refer to the following screenshots below based on Android and iOS platforms.</p><p><strong>Android</strong></p><p><em>[Image: 1658]</em></p><p><strong>iOS</strong></p><p><em>[Image: 1648]</em></p>',16)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
